values (
  'a0000000-0000-4000-8000-000000000350',
  'a0000000-0000-4000-8000-000000000203',
  'Alternate Path',
  'Not engaged student warm-up.',
  'alternative'
)
on conflict (id) do update set
  name = excluded.name,
  description = excluded.description,
  path_type = excluded.path_type;

